<template>
  <view class="page-container">
    <!-- 顶部标题栏 -->
    <view class="nav-bar">
      <!-- <u-icon name="arrow-left" size="24" color="#000000" @click="goBack"></u-icon> -->
      <!-- <text class="nav-title">药品赠药/援助项目</text> -->
      <!-- <view class="nav-placeholder"></view> -->
    </view>

    <!-- 加载状态 -->
    <view v-if="loading" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <!-- 空状态 -->
    <view v-else-if="projects.length === 0" class="empty-state">
      <u-empty mode="data" text="暂无援助项目"></u-empty>
    </view>

    <!-- 项目列表 -->
    <scroll-view v-else scroll-y class="content-scroll">
      <view class="project-list">
        <view
          v-for="project in projects"
          :key="project.id"
          class="project-card"
        >
          <text class="project-name">{{ project.name }}</text>

          <text class="project-info">
            条件：{{ project.condition }} | 周期：{{ project.period }}
          </text>

          <text class="project-desc">{{ project.desc }}</text>

          <!-- 状态标签 -->
          <view class="status-row">
            <u-tag 
              :text="project.status === 'active' ? '进行中' : '已截止'" 
              :type="project.status === 'active' ? 'success' : 'error'" 
              size="mini"
            ></u-tag>
            <text class="deadline-text">截止：{{ project.deadline }}</text>
          </view>

          <!-- 操作按钮 -->
          <view class="action-buttons">
            <u-button 
              size="mini" 
              type="primary" 
              @click="apply(project)"
              :disabled="project.status !== 'active'"
            >
              申请援助
            </u-button>
            <u-button size="mini" plain @click="checkProgress(project)">
              查询进度
            </u-button>
            <u-button size="mini" plain @click="downloadGuide(project)">
              下载指南
            </u-button>
          </view>
        </view>
      </view>
    </scroll-view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import request from '@/utils/request'

interface Project {
  id: number
  name: string
  condition: string
  period: string
  desc: string
  status: 'active' | 'expired'
  deadline: string
  guideUrl?: string
}

const projects = ref<Project[]>([])
const loading = ref(false)

const fetchProjects = async () => {
  loading.value = true
  try {
    const res = await request.get('/api/resource/drug/donations')
    projects.value = res.data?.list || res.data || []
  } catch (error) {
    uni.__f__('error','at pages/resource/drug/DonationProject.vue:94','获取援助项目列表失败:', error)
    projects.value = []
    uni.showToast({ title: '加载项目列表失败，请稍后再试', icon: 'none' })
  } finally {
    loading.value = false
  }
}

const apply = (project: Project) => {
  if (project.status !== 'active') {
    uni.showToast({ title: '该项目已截止申请', icon: 'none' })
    return
  }
  uni.navigateTo({
    url: `/pages/resource/drug/DonationApply?projectId=${project.id}`
  })
}

const checkProgress = async (project: Project) => {
  try {
    const res = await request.get(`/api/resource/drug/donations/${project.id}/progress`)
    const data = res.data
    
    uni.showModal({
      title: '申请进度',
      content: `项目：${data.projectName}\n状态：${data.statusText}\n提交时间：${data.submitTime}\n更新时间：${data.updateTime}`,
      showCancel: false
    })
  } catch (error) {
    uni.__f__('error','at pages/resource/drug/DonationProject.vue:123','查询进度失败:', error)
    uni.showModal({
      title: '申请进度',
      content: '暂无申请记录',
      showCancel: false
    })
  }
}

const downloadGuide = async (project: Project) => {
  if (!project.guideUrl) {
    uni.showToast({ title: '暂无指南文件', icon: 'none' })
    return
  }

  uni.showLoading({ title: '下载中...' })
  try {
    let downloadUrl = project.guideUrl
    if (!downloadUrl.startsWith('http')) {
      const BASE_URL = import.meta.env.VITE_API_BASE_URL || 'https://your-api-domain.com'
      downloadUrl = BASE_URL.replace(/\/+$/, '') + downloadUrl
    }

    uni.downloadFile({
      url: downloadUrl,
      success: (res) => {
        if (res.statusCode === 200) {
          uni.openDocument({
            filePath: res.tempFilePath,
            showMenu: true,
            success: () => {
              uni.hideLoading()
              uni.showToast({ title: '打开成功', icon: 'success' })
            },
            fail: () => {
              uni.hideLoading()
              uni.showToast({ title: '打开文件失败', icon: 'none' })
            }
          })
        } else {
          uni.hideLoading()
          uni.showToast({ title: '下载失败', icon: 'none' })
        }
      },
      fail: () => {
        uni.hideLoading()
        uni.showToast({ title: '下载失败，请检查网络', icon: 'none' })
      }
    })
  } catch (error) {
    uni.hideLoading()
    uni.__f__('error','at pages/resource/drug/DonationProject.vue:174','下载指南失败:', error)
    uni.showToast({ title: '下载失败，请稍后再试', icon: 'none' })
  }
}

const goBack = () => {
  uni.navigateBack()
}

onMounted(() => {
  fetchProjects()
})
</script>

